mapper.select:
select r.id, r.role_name as roleName, JSON_LENGTH(r.permissions) as permissions, count(u.id) as users, r.`desc`, r.systemic from tb_role r left join tb_user u on JSON_CONTAINS(u.role, CAST(r.id as char ))
and r.role_name like concat('%', #{roleName}, '%')
group by r.id order by r.id limit #{start}, #{length}

mapper.insert:
insert into tb_role set
    role_name = #{roleName},
    permissions = #{permissions}

    , `desc` = #{desc}

mapper.select:
select p.id, m.module_name as moduleName, a.action_name as actionName from tb_permission p
       left join tb_module m on p.module_id = m.id
       left join tb_action a on p.action_id = a.id
       JOIN tb_role r ON r.id = #{id}
WHERE JSON_CONTAINS(r.permissions, CAST(p.id AS CHAR))
order by p.id;

mapper.update:
update tb_role set
    role_name = #{roleName},
    permissions = #{permissions},
    `desc` = #{desc}
where id = #{id} and id != 0;

mapper.select:
SELECT NOT EXISTS ( SELECT 1 FROM tb_role r JOIN tb_user u ON JSON_CONTAINS(u.role, CAST(r.id AS CHAR)) WHERE r.id IN
#{id}
LIMIT 1 ) AS result
